(27,1,'2026-06-02 20:53:56','2026-06-02 18:53:56','<!-- wp:group {\"align\":\"full\",\"style\":{\"color\":{\"background\":\"#e0cea5\",\"text\":\"#4d3c29\"},\"spacing\":{\"padding\":{\"top\":\"80px\",\"bottom\":\"80px\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group alignfull has-text-color has-background\" style=\"color:#4d3c29;background-color:#e0cea5;padding-top:80px;padding-bottom:80px\"><!-- wp:heading {\"level\":1,\"style\":{\"color\":{\"text\":\"#4d3c29\"},\"typography\":{\"fontFamily\":\"monospace\",\"textAlign\":\"center\"}}} -->\n<h1 class=\"wp-block-heading has-text-align-center has-text-color\" style=\"color:#4d3c29;font-family:monospace\">Contactez-nous</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#4d3c29\"},\"typography\":{\"fontFamily\":\"sans-serif\",\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#4d3c29;font-family:sans-serif\">Vous avez des questions sur notre agence ou sur notre expérience immersive ? Vous souhaitez collaborer avec nous ou rejoindre notre équipe ? N\'hésitez pas à nous envoyer un message. Notre équipe vous répondra dans les plus brefs délais.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:html -->\n<style>.wpcf7 input[type=\"submit\"], .wpcf7 button[type=\"submit\"], .wpcf7-submit { background-color: #af6743 !important; color: #e0cea5 !important; border-color: #af6743 !important; }</style>\n<!-- /wp:html -->\n\n<!-- wp:shortcode -->\n[contact-form-7 id=\"77b7730\" title=\"Contact form 1\"]\n<!-- /wp:shortcode --></div>\n<!-- /wp:group -->','Contact','','publish','closed','closed','','contact','','','2026-06-04 23:21:26','2026-06-04 21:21:26','',0,'https://sae202-agence.mmi25a07.mmi-troyes.fr/?page_id=27',0,'page','',0),
