ground-color:#ffffff;padding-top:24px;padding-right:24px;padding-bottom:24px;padding-left:24px;box-shadow:var(--wp--preset--shadow--natural)\"><!-- wp:image {\"id\":114,\"width\":\"120px\",\"height\":\"120px\",\"scale\":\"cover\",\"sizeSlug\":\"large\",\"linkDestination\":\"none\",\"align\":\"center\",\"className\":\"is-style-rounded\"} -->\n<figure class=\"wp-block-image aligncenter size-large is-resized is-style-rounded\"><img src=\"https://sae202-agence.mmi25a07.mmi-troyes.fr/wp-content/uploads/2026/06/exemple.jpg\" alt=\"Giorgi\" class=\"wp-image-114\" style=\"object-fit:cover;width:120px;height:120px\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#4d3c29\"},\"typography\":{\"fontWeight\":\"700\",\"textAlign\":\"center\"}}} -->\n<h3 class=\"wp-block-heading has-text-align-center has-text-color\" style=\"color:#4d3c29;font-weight:700\">Giorgi</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#46401f\"},\"typography\":{\"fontSize\":\"14px\",\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#46401f;font-size:14px\">Développeur Web</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#4d3c29\"},\"typography\":{\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#4d3c29\">En charge de la création du site vitrine WordPress, de l\'administration du serveur VPS et du développement de la future plateforme de réservation en PHP/MVC.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#af6743\"},\"typography\":{\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#af6743\"><a href=\"/membres/giorgi\">En savoir plus ➜</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"24px\",\"right\":\"24px\",\"bottom\":\"24px\",\"left\":\"24px\"}},\"border\":{\"radius\":\"16px\"},\"color\":{\"background\":\"#ffffff\"},\"shadow\":\"var:preset|shadow|natural\"},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"border-radius:16px;background-color:#ffffff;padding-top:24px;padding-right:24px;padding-bottom:24px;padding-left:24px;box-shadow:var(--wp--preset--shadow--natural)\"><!-- wp:image {\"id\":114,\"width\":\"120px\",\"height\":\"120px\",\"scale\":\"cover\",\"sizeSlug\":\"large\",\"linkDestination\":\"none\",\"align\":\"center\",\"className\":\"is-style-rounded\"} -->\n<figure class=\"wp-block-image aligncenter size-large is-resized is-style-rounded\"><img src=\"https://sae202-agence.mmi25a07.mmi-troyes.fr/wp-content/uploads/2026/06/exemple.jpg\" alt=\"Ophélia\" class=\"wp-image-114\" style=\"object-fit:cover;width:120px;height:120px\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#4d3c29\"},\"typography\":{\"fontWeight\":\"700\",\"textAlign\":\"center\"}}} -->\n<h3 class=\"wp-block-heading has-text-align-center has-text-color\" style=\"color:#4d3c29;font-weight:700\">Ophélia</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#46401f\"},\"typography\":{\"fontSize\":\"14px\",\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#46401f;font-size:14px\">Designer Graphique</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#4d3c29\"},\"typography\":{\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#4d3c29\">Responsable de l\'identité visuelle de l\'agence, de la création du logo, de la charte graphique globale et des maquettes interactives sur Figma.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#af6743\"},\"typography\":{\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#af6743\"><a href=\"/membres/ophelia\">En savoir plus ➜</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"24px\",\"right\":\"24px\",\"bottom\":\"24px\",\"left\":\"24px\"}},\"border\":{\"radius\":\"16px\"},\"color\":{\"background\":\"#ffffff\"},\"shadow\":\"var:preset|shadow|natural\"},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"border-radius:16px;background-color:#ffffff;padding-top:24px;padding-right:24px;padding-bottom:24px;padding-left:24px;box-shadow:var(--wp--preset--shadow--natural)\"><!-- wp:image {\"id\":114,\"width\":\"120px\",\"height\":\"120px\",\"scale\":\"cover\",\"sizeSlug\":\"large\",\"linkDestination\":\"none\",\"align\":\"center\",\"className\":\"is-style-rounded\"} -->\n<figure class=\"wp-block-image aligncenter size-large is-resized is-style-rounded\"><img src=\"https://sae202-agence.mmi25a07.mmi-troyes.fr/wp-content/uploads/2026/06/exemple.jpg\" alt=\"Noah\" class=\"wp-image-114\" style=\"object-fit:cover;width:120px;height:120px\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#4d3c29\"},\"typography\":{\"fontWeight\":\"700\",\"textAlign\":\"center\"}}} -->\n<h3 class=\"wp-block-heading has-text-align-center has-text-color\" style=\"color:#4d3c29;font-weight:700\">Noah</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#46401f\"},\"typography\":{\"fontSize\":\"14px\",\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#46401f;font-size:14px\">Responsable Audiovisuel &amp; Budget</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#4d3c29\"},\"typography\":{\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#4d3c29\">S\'occupe de la scénarisation, du storyboard, du tournage et du montage de la vidéo promotionnelle (teaser), ainsi que de la gestion budgétaire.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#af6743\"},\"typography\":{\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#af6743\"><a href=\"/membres/noah\">En savoir plus ➜</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"24px\",\"right\":\"24px\",\"bottom\":\"24px\",\"left\":\"24px\"}},\"border\":{\"radius\":\"16px\"},\"color\":{\"background\":\"#ffffff\"},\"shadow\":\"var:preset|shadow|natural\"},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"border-radius:16px;background-color:#ffffff;padding-top:24px;padding-right:24px;padding-bottom:24px;padding-left:24px;box-shadow:var(--wp--preset--shadow--natural)\"><!-- wp:image {\"id\":114,\"width\":\"120px\",\"height\":\"120px\",\"scale\":\"cover\",\"sizeSlug\":\"large\",\"linkDestination\":\"none\",\"align\":\"center\",\"className\":\"is-style-rounded\"} -->\n<figure class=\"wp-block-image aligncenter size-large is-resized is-style-rounded\"><img src=\"https://sae202-agence.mmi25a07.mmi-troyes.fr/wp-content/uploads/2026/06/exemple.jpg\" alt=\"Evaelle\" class=\"wp-image-114\" style