202-agence.mmi25a07.mmi-troyes.fr/contact/\">Nous contacter</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group --></aside>\n<!-- /wp:group -->\n\n<!-- wp:group {\"align\":\"full\",\"style\":{\"color\":{\"background\":\"#e0cea5\"},\"spacing\":{\"padding\":{\"top\":\"var:preset|spacing|60\",\"bottom\":\"var:preset|spacing|60\",\"left\":\"var:preset|spacing|40\",\"right\":\"var:preset|spacing|40\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group alignfull has-background\" style=\"background-color:#e0cea5;padding-top:var(--wp--preset--spacing--60);padding-right:var(--wp--preset--spacing--40);padding-bottom:var(--wp--preset--spacing--60);padding-left:var(--wp--preset--spacing--40)\"><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"color\":{\"text\":\"#4d3c29\"}},\"fontFamily\":\"p-22-typewriter\"} -->\n<h2 class=\"wp-block-heading has-text-align-center has-text-color has-p-22-typewriter-font-family\" style=\"color:#4d3c29\">Notre Équipe</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#4d3c29\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#4d3c29\">Rencontre les talents passionnés qui font vibrer notre agence</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:columns {\"align\":\"wide\",\"style\":{\"spacing\":{\"blockGap\":{\"left\":\"var:preset|spacing|30\"}}}} -->\n<div class=\"wp-block-columns alignwide\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"24px\",\"right\":\"24px\",\"bottom\":\"24px\",\"left\":\"24px\"}},\"border\":{\"radius\":\"16px\"},\"color\":{\"background\":\"#ffffff\"},\"shadow\":\"var:preset|shadow|natural\"},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"border-radius:16px;background-color:#ffffff;padding-top:24px;padding-right:24px;padding-bottom:24px;padding-left:24px;box-shadow:var(--wp--preset--shadow--natural)\"><!-- wp:image {\"align\":\"center\",\"sizeSlug\":\"large\",\"linkDestination\":\"none\",\"className\":\"is-style-rounded\"} -->\n<figure class=\"wp-block-image aligncenter size-large is-style-rounded\"><img src=\"https://intranet.iut-troyes.univ-reims.fr/media/cache/thumb/upload/etudiants/22503006.jpg\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":3,\"style\":{\"color\":{\"text\":\"#4d3c29\"},\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"700\"}}} -->\n<h3 class=\"wp-block-heading has-text-align-center has-text-color\" style=\"color:#4d3c29;font-style:normal;font-weight:700\">Giorgi</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#46401f\"},\"typography\":{\"fontSize\":\"0.875rem\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#46401f;font-size:0.875rem\">Développeur Web</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#4d3c29\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#4d3c29\">En charge de la création du site vitrine WordPress, de l\'administration du serveur VPS et du développement de la future plateforme de réservation en PHP/MVC.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#af6743\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#af6743\"><a href=\"/membres/giorgi\">En savoir plus ➔</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"24px\",\"right\":\"24px\",\"bottom\":\"24px\",\"left\":\"24px\"}},\"border\":{\"radius\":\"16px\"},\"color\":{\"background\":\"#ffffff\"},\"shadow\":\"var:preset|shadow|natural\"},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\