has-contrast-background-color has-text-color has-background has-link-color\" style=\"margin-top:0;margin-bottom:0;padding-top:var(--wp--preset--spacing--50);padding-bottom:var(--wp--preset--spacing--50)\"><!-- wp:columns {\"align\":\"wide\",\"style\":{\"spacing\":{\"blockGap\":{\"top\":\"var:preset|spacing|60\",\"left\":\"var:preset|spacing|80\"}}}} -->\n<div class=\"wp-block-columns alignwide\"><!-- wp:column {\"verticalAlignment\":\"center\",\"width\":\"50%\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\" style=\"flex-basis:50%\"><!-- wp:heading {\"className\":\"wp-block-heading\"} -->\n<h2 class=\"wp-block-heading\">Le Concept</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\">Un événement immersif saisonnier de 24 heures, mêlant enquête, théâtre vivant, repas, nuitée et escape game. Par groupes de 5 à 6 personnes, infiltrez une secte afin de retrouver votre ami disparu. Sous couverture, vivez comme les membres de la communauté sans éveiller les soupçons…</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"center\",\"width\":\"50%\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-column is-vertically-aligned-center\" style=\"flex-basis:50%\"><!-- wp:image {\"id\":101,\"aspectRatio\":\"1\",\"scale\":\"cover\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"https://sae202-agence.mmi25a07.mmi-troyes.fr/wp-content/uploads/2026/06/image-1.webp\" alt=\"\" class=\"wp-image-101\" style=\"aspect-ratio:1;object-fit:cover\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"aside\",\"metadata\":{\"patternName\":\"twentytwentyfive/cta-newsletter\",\"name\":\"Newsletter sign-up\",\"categories\":[\"call-to-action\"]},\"align\":\"full\",\"className\":\"is-style-section-3\",\"style\":{\"