lor:rgba(0, 0, 0, 0)\" class=\"has-inline-color has-custom-color-1-color\">Le Cercle des Égarés</mark></h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|base\"}}}},\"textColor\":\"base\"} -->\n<p class=\"has-base-color has-text-color has-link-color\"><mark style=\"background-color:rgba(0, 0, 0, 0)\" class=\"has-inline-color has-custom-color-5-color\">Infiltrez une secte en pleine nature. Une expérience immersive de 24h. Aurez-vous le courage de découvrir la vérité ?</mark></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"blockGap\":\"var:preset|spacing|30\"}},\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"left\"}} -->\n<div class=\"wp-block-group\"><!-- wp:heading {\"level\":3,\"style\":{\"typography\":{\"textTransform\":\"uppercase\",\"letterSpacing\":\"1px\",\"fontStyle\":\"normal\",\"fontWeight\":\"600\"}},\"fontSize\":\"small\"} -->\n<h3 class=\"wp-block-heading has-small-font-size\" style=\"font-style:normal;font-weight:600;letter-spacing:1px;text-transform:uppercase\"></h3>\n<!-- /wp:heading -->\n\n<!-- wp:group {\"layout\":{\"type\":\"flex\",\"flexWrap\":\"wrap\"}} -->\n<div class=\"wp-block-group\"><!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|base\"}}}},\"textColor\":\"base\"} -->\n<p class=\"has-base-color has-text-color has-link-color\"></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"metadata\":{\"patternName\":\"twentytwentyfive/heading-and-paragraph-with-image\",\"name\":\"Heading and paragraph with image on the right\",\"description\":\"A two-column section with a heading and paragraph on the left, and an image on the right.\",\"categories\":[\"about\"]},\"align\":\"full\",\"className\":\"is-style-section-4\",\"style\":{\"spacing\":{\"padding\":{\"top\":\"var:preset|spacing|50\",\"bottom\":\"var:preset|spacing|50\"},\"margin\":{\"top\":\"0\",\"bottom\":\"0\"}},\"elements\":{\"link\":{\"color\":{\"text\":\"#e0cea5\"}},\"heading\":{\"color\":{\"text\":\"#e0cea5\"}}},\"color\":{\"text\":\"#e0cea5\"}},\"backgroundColor\":\"custom-color-1\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group alignfull is-style-section-4 has-custom-color-1-background-color has-text-color has-background has-link-color\" style=\"color:#e0cea5;margin-top:0;margin-bottom:0;padding-top:var(--wp--preset--spacing--50);padding-bottom:var(--wp--preset--spacing--50)\"><!-- wp:columns {\"align\":\"wide\",\"style\":{\"spacing\":{\"blockGap\":{\"top\":\"var:preset|spacing|60\",\"left\":\"var:preset|spacing|80\"}}}} -->\n<div class=\"wp-block-columns alignwide\"><!-- wp:column {\"verticalAlignment\":\"center\",\"width\":\"50%\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\" style=\"flex-basis:50%\"><!-- wp:heading {\"className\":\"wp-block-heading\",\"style\":{\"typography\":{\"textAlign\":\"center\"}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\">Le Concept</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"style\":{\"typography\":{\"textAlign\":\"left\"}},\"fontSize\":\"medium\"} -->\n<p class=\"has-text-align-left has-medium-font-size\">Un événement immersif saisonnier de 24 heures, mêlant enquête, théâtre vivant, repas, nuitée et escape game. Par groupes de 5 à 6 personnes, infiltrez une secte afin de retrouver votre ami disparu. Sous couverture, vivez comme les membres de la communauté sans éveiller les soupçons…</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"center\",\"width\":\"50%\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-column is-vertically-aligned-center\" style=\"flex-basis:50%\"><!-- wp:image {\"id\":217,\"width\":\"318px\",\"height\":\"auto\",\"aspectRatio\":\"1\",\"scale\":\"cover\",\"sizeSlug\":\"full\",\"l