lor:rgba(0, 0, 0, 0)\" class=\"has-inline-color has-custom-color-1-color\">Le Cercle des Égarés</mark></h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|base\"}}}},\"textColor\":\"base\"} -->\n<p class=\"has-base-color has-text-color has-link-color\"><mark style=\"background-color:rgba(0, 0, 0, 0)\" class=\"has-inline-color has-custom-color-5-color\">Infiltrez une secte en pleine nature. Une expérience immersive de 24h. Aurez-vous le courage de découvrir la vérité ?</mark></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"blockGap\":\"var:preset|spacing|30\"}},\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"left\"}} -->\n<div class=\"wp-block-group\"><!-- wp:heading {\"level\":3,\"style\":{\"typography\":{\"textTransform\":\"uppercase\",\"letterSpacing\":\"1px\",\"fontStyle\":\"normal\",\"fontWeight\":\"600\"}},\"fontSize\":\"small\"} -->\n<h3 class=\"wp-block-heading has-small-font-size\" style=\"font-style:normal;font-weight:600;letter-spacing:1px;text-transform:uppercase\"></h3>\n<!-- /wp:heading -->\n\n<!-- wp:group {\"layout\":{\"type\":\"flex\",\"flexWrap\":\"wrap\"}} -->\n<div class=\"wp-block-group\"><!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|base\"}}}},\"textColor\":\"base\"} -->\n<p class=\"has-base-color has-text-color has-link-color\"></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"metadata\":{\"patternName\":\"twentytwentyfive/heading-and-paragraph-with-image\",\"name\":\"Heading and paragraph with image on the right\",\"description\":\"A two-column section with a heading and paragraph on the left, and an image on the right.\",\"categories\":[\"about\"]},\"align\":\"full\",\"className\":\"is-style-section-4\",\"style\":{\"spacing\":{\"padding\":{\"top\":\"var:preset|spacing|50\",\"bottom\":\"var:preset|spacing|50\"},\"margin\":{\"top\":\"0\",\"bottom\":\"0\"}},\"elements\":{\"link\":{\"color\":{\"text\":\"#e0cea5\"}},\"heading\":{\"color\":{\"text\":\"#e0cea5\"}}},\"color\":{\"text\":\"#e0cea5\"}},\"backgroundColor\":\"custom-color-1\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group alignfull is-style-section-4 has-custom-color-1-background-color has-text-color has-background has-link-color\" style=\"color:#e0cea5;margin-top:0;margin-bottom:0;padding-top:var(--wp--preset--spacing--50);padding-bottom:var(--wp--preset--spacing--50)\"><!-- wp:columns {\"align\":\"wide\",\"style\":{\"spacing\":{\"blockGap\":{\"top\":\"var:preset|spacing|60\",\"left\":\"var:preset|spacing|80\"}}}} -->\n<div class=\"wp-block-columns alignwide\"><!-- wp:column {\"verticalAlignment\":\"center\",\"width\":\"50%\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\" style=\"flex-basis:50%\"><!-- wp:heading {\"className\":\"wp-block-heading\",\"style\":{\"typography\":{\"textAlign\":\"center\"}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\">Le Concept</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"style\":{\"typography\":{\"textAlign\":\"left\"}},\"fontSize\":\"medium\"} -->\n<p class=\"has-text-align-left has-medium-font-size\">Un événement immersif saisonnier de 24 heures, mêlant enquête, théâtre vivant, repas, nuitée et escape game. Par groupes de 5 à 6 personnes, infiltrez une secte afin de retrouver votre ami disparu. Sous couverture, vivez comme les membres de la communauté sans éveiller les soupçons…</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"center\",\"width\":\"50%\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-column is-vertically-aligned-center\" style=\"flex-basis:50%\"><!-- wp:image {\"id\":230,\"width\":\"358px\",\"height\":\"auto\",\"aspectRatio\":\"1.7660076718796105\",\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large is-resized\"><img src=\"https://sae202-agence.mmi25a07.mmi-troyes.fr/wp-content/uploads/2026/06/peakpx-3-1024x576.jpg\" alt=\"\" class=\"wp-image-230\" style=\"aspect-ratio:1.7660076718796105;width:358px;height:auto\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"aside\",\"metadata\":{\"patternName\":\"twentytwentyfive/cta-newsletter\",\"name\":\"Newsletter sign-up\",\"categories\":[\"call-to-action\"]},\"align\":\"full\",\"className\":\"is-style-section-3\",\"style\":{\"spacing\":{\"padding\":{\"right\":\"var:preset|spacing|50\",\"left\":\"var:preset|spacing|50\",\"top\":\"var:preset|spacing|50\",\"bottom\":\"var:preset|spacing|50\"},\"margin\":{\"top\":\"0\",\"bottom\":\"0\"}},\"dimensions\":{\"minHeight\":\"\"}},\"backgroundColor\":\"custom-color-3\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"800px\"}} -->\n<aside class=\"wp-block-group alignfull is-style-section-3 has-custom-color-3-background-color has-background\" style=\"margin-top:0;margin-bottom:0;padding-top:var(--wp--preset--spacing--50);padding-right:var(--wp--preset--spacing--50);padding-bottom:var(--wp--preset--spacing--50);padding-left:var(--wp--preset--spacing--50)\"><!-- wp:group {\"style\":{\"dimensions\":{\"minHeight\":\"360px\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"0\"}}},\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"verticalAlignment\":\"center\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-group\" style=\"min-height:360px;margin-top:0;margin-bottom:0\"><!-- wp:heading {\"style\":{\"typography\":{\"textAlign\":\"center\"}},\"fontSize\":\"xx-large\"} -->\n<h2 class=\"wp-block-heading has-text-align-center has-xx-large-font-size\"><strong><mark style=\"background-color:rgba(0, 0, 0, 0);color:#FBFAF3\" class=\"has-inline-color\">Prêt à tenter l\'aventure ?</mark></strong></h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"is-style-text-subtitle\",\"style\":{\"typography\":{\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center is-style-text-subtitle\"><strong><mark style=\"background-color:rgba(0, 0, 0, 0);color:#FBFAF3\" class=\"has-inline-color\">Rejoignez-nous pour une expérience inoubliable.</mark></strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:spacer {\"height\":\"0px\",\"style\":{\"layout\":{\"flexSize\":\"20px\",\"selfStretch\":\"fixed\"}}} -->\n<div style=\"height:0px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"style\":{\"typography\":{\"textAlign\":\"center\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-text-align-center wp-element-button\" href=\"https://sae202-agence.mmi25a07.mmi-troyes.fr/contact/\">Nous contacter</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group --></aside>\n<!-- /wp:group -->\n\n<!-- wp:group {\"align\":\"full\",\"style\":{\"color\":{\"background\":\"#e0cea5\"},\"spacing\":{\"padding\":{\"top\":\"var:preset|spacing|60\",\"bottom\":\"var:preset|spacing|60\",\"left\":\"var:preset|spacing|40\",\"right\":\"var:preset|spacing|40\"},\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group alignfull has-background\" style=\"background-color:#e0cea5;margin-top:0px;margin-bottom:0px;padding-top:var(--wp--preset--spacing--60);padding-right:var(--wp--preset--spacing--40);padding-bottom:var(--wp--preset--spacing--60);padding-left:var(--wp--preset--spacing--40)\"><!-- wp:heading {\"style\":{\"color\":{\"text\":\"#4d3c29\"},\"typography\":{\"textAlign\":\"center\"}},\"fontFamily\":\"p-22-typewriter\"} -->\n<h2 class=\"wp-block-heading has-text-align-center has-text-color has-p-22-typewriter-font-family\" style=\"color:#4d3c29\">Notre Équipe</h2>\n<!-- /wp:heading -->\n\n<!-- wp:columns {\"align\":\"wide\",\"style\":{\"spacing\":{\"blockGap\":{\"left\":\"var:preset|spacing|30\"}}}} -->\n<div class=\"wp-block-columns alignwide\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"24px\",\"right\":\"24px\",\"bottom\":\"24px\",\"left\":\"24px\"}},\"border\":{\"radius\":\"16px\"},\"color\":{\"background\":\"#ffffff\"},\"shadow\":\"var:preset|shadow|natural\"},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"border-radius:16px;background-color:#ffffff;padding-top:24px;padding-right:24px;padding-bottom:24px;padding-left:24px;box-shadow:var(--wp--preset--shadow--natural)\"><!-- wp:image {\"sizeSlug\":\"large\",\"linkDestination\":\"none\",\"align\":\"center\",\"className\":\"is-style-rounded\"} -->\n<figure class=\"wp-block-image aligncenter size-large is-style-rounded\"><img src=\"https://intranet.iut-troyes.univ-reims.fr/media/cache/thumb/upload/etudiants/22503006.jpg\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#4d3c29\"},\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"700\",\"textAlign\":\"center\"}}} -->\n<h3 class=\"wp-block-heading has-text-align-center has-text-color\" style=\"color:#4d3c29;font-style:normal;font-weight:700\">Giorgi</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#46401f\"},\"typography\":{\"fontSize\":\"0.875rem\",\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#46401f;font-size:0.875rem\">Développeur Web</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#4d3c29\"},\"typography\":{\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#4d3c29\">En charge de la création du site vitrine WordPress, de l\'administration du serveur VPS et du développement de la future plateforme de réservation en PHP/MVC.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#af6743\"},\"typography\":{\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#af6743\"><a href=\"/membres/giorgi\">En savoir plus ➔</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"24px\",\"right\":\"24px\",\"bottom\":\"24px\",\"left\":\"24px\"}},\"border\":{\"radius\":\"16px\"},\"color\":{\"background\":\"#ffffff\"},\"shadow\":\"var:preset|shadow|natural\"},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"border-radius:16px;background-color:#ffffff;padding-top:24px;padding-right:24px;padding-bottom:24px;padding-left:24px;box-shadow:var(--wp--preset--shadow--natural)\"><!-- wp:image {\"sizeSlug\":\"large\",\"linkDestination\":\"none\",\"align\":\"center\",\"className\":\"is-style-rounded\"} -->\n<figure class=\"wp-block-image aligncenter size-large is-style-rounded\"><img src=\"https://intranet.iut-troyes.univ-reims.fr/media/cache/thumb/upload/etudiants/22506443.jpg\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#4d3c29\"},\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"700\",\"textAlign\":\"center\"}}} -->\n<h3 class=\"wp-block-heading has-text-align-center has-text-color\" style=\"color:#4d3c29;font-style:normal;font-weight:700\">Ophélia</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#46401f\"},\"typography\":{\"fontSize\":\"0.875rem\",\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#46401f;font-size:0.875rem\">Designer Graphique</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#4d3c29\"},\"typography\":{\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#4d3c29\">Responsable de l\'identité visuelle de l\'agence, de la création du logo, de la charte graphique globale et des maquettes interactives sur Photoshop/Illustrator &amp;Figma.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#af6743\"},\"typography\":{\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#af6743\"><a href=\"/membres/ophelia\">En savoir plus ➔</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"24px\",\"right\":\"24px\",\"bottom\":\"24px\",\"left\":\"24px\"}},\"border\":{\"radius\":\"16px\"},\"color\":{\"background\":\"#ffffff\"},\"shadow\":\"var:preset|shadow|natural\"},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"border-radius:16px;background-color:#ffffff;padding-top:24px;padding-right:24px;padding-bottom:24px;padding-left:24px;box-shadow:var(--wp--preset--shadow--natural)\"><!-- wp:image {\"sizeSlug\":\"large\",\"linkDestination\":\"none\",\"align\":\"center\",\"className\":\"is-style-rounded\"} -->\n<figure class=\"wp-block-image aligncenter size-large is-style-rounded\"><img src=\"https://intranet.iut-troyes.univ-reims.fr/media/cache/thumb/upload/etudiants/22505125.jpg\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#4d3c29\"},\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"700\",\"textAlign\":\"center\"}}} -->\n<h3 class=\"wp-block-heading has-text-align-center has-text-color\" style=\"color:#4d3c29;font-style:normal;font-weight:700\">Noah</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#46401f\"},\"typography\":{\"fontSize\":\"0.875rem\",\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#46401f;font-size:0.875rem\">Responsable Audiovisuel &amp; Budget</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#4d3c29\"},\"typography\":{\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#4d3c29\">S\'occupe de la scénarisation, du storyboard, du tournage et du montage de la vidéo promotionnelle (teaser), ainsi que de la gestion budgétaire.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#af6743\"},\"typography\":{\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#af6743\"><a href=\"/membres/noah\">En savoir plus ➔</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"24px\",\"right\":\"24px\",\"bottom\":\"24px\",\"left\":\"24px\"}},\"border\":{\"radius\":\"16px\"},\"color\":{\"background\":\"#ffffff\"},\"shadow\":\"var:preset|shadow|natural\"},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"border-radius:16px;background-color:#ffffff;padding-top:24px;padding-right:24px;padding-bottom:24px;padding-left:24px;box-shadow:var(--wp--preset--shadow--natural)\"><!-- wp:image {\"sizeSlug\":\"large\",\"linkDestination\":\"none\",\"align\":\"center\",\"className\":\"is-style-rounded\"} -->\n<figure class=\"wp-block-image aligncenter size-large is-style-rounded\"><img src=\"https://intranet.iut-troyes.univ-reims.fr/media/cache/thumb/upload/etudiants/22503375.jpg\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#4d3c29\"},\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"700\",\"textAlign\":\"center\"}}} -->\n<h3 class=\"wp-block-heading has-text-align-center has-text-color\" style=\"color:#4d3c29;font-style:normal;font-weight:700\">Evaelle</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#46401f\"},\"typography\":{\"fontSize\":\"0.875rem\",\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#46401f;font-size:0.875rem\">Responsable Marketing &amp; Communication</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#4d3c29\"},\"typography\":{\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#4d3c29\">En charge de l\'analyse concurrentielle (benchmark), de l\'étude des personas, de la proposition de valeur et de la stratégie de communication globale.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"className\":\"has-text-color\",\"style\":{\"color\":{\"text\":\"#af6743\"},\"typography\":{\"textAlign\":\"center\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#af6743\"><a href=\"/membres/evaelle\">En savoir plus ➔</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->','Accueil','','inherit','closed','closed','','11-revision-v1','','','2026-06-05 11:54:44','2026-06-05 09:54:44','',11,'https://sae202-agence.mmi25a07.mmi-troyes.fr/?p=233',0,'revision','',0);
