(237,1,'2026-06-05 12:27:52','2026-06-05 10:27:52','<!-- wp:group {\"metadata\":{\"patternName\":\"twentytwentyfive/hero-podcast\",\"name\":\"Hero podcast\",\"categories\":[\"banner\"]},\"align\":\"full\",\"className\":\"is-style-default\",\"style\":{\"spacing\":{\"padding\":{\"top\":\"var:preset|spacing|60\",\"bottom\":\"var:preset|spacing|60\"},\"margin\":{\"top\":\"0\",\"bottom\":\"0\"}},\"color\":{\"background\":\"#e0cea5\"},\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|custom-color-5\"}}}},\"textColor\":\"custom-color-5\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group alignfull is-style-default has-custom-color-5-color has-text-color has-background has-link-color\" style=\"background-color:#e0cea5;margin-top:0;margin-bottom:0;padding-top:var(--wp--preset--spacing--60);padding-bottom:var(--wp--preset--spacing--60)\"><!-- wp:columns {\"align\":\"wide\",\"style\":{\"spacing\":{\"blockGap\":{\"top\":\"var:preset|spacing|60\",\"left\":\"var:preset|spacing|60\"}}}} -->\n<div class=\"wp-block-columns alignwide\"><!-- wp:column {\"width\":\"40%\"} -->\n<div class=\"wp-block-column\" style=\"flex-basis:40%\"><!-- wp:image {\"lightbox\":{\"enabled\":false},\"sizeSlug\":\"large\",\"linkDestination\":\"custom\",\"className\":\"is-style-default animated zoomIn slow\"} -->\n<figure class=\"wp-block-image size-large is-style-default animated zoomIn slow\"><img src=\"https://thegreatescapegame.co.uk/wp-content/uploads/2023/10/blog02.jpg\" alt=\"\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"center\",\"width\":\"60%\",\"style\":{\"spacing\":{\"blockGap\":\"var:preset|spacing|40\"}}} -->\n<div class=\"wp-block-column is-vertically-aligned-center\" style=\"flex-basis:60%\"><!-- wp:heading {\"className\":\"animated fadeInUp delay-200ms\",\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|base\"}}}},\"textColor\":\"base\",\"fontSize\":\"xx-large\"} -->\n<h2 clas